// ── Portal & instance ───────────────────────────
flow.set('PORTAL_ID', '48e7da87b65f');

// ── Battery protection ──────────────────────────
flow.set('MIN_SOC', 20);              // % — stop EV charging below this
flow.set('MAX_BATT_DISCHARGE', 500);  // W  — max battery discharge to top up EV

// ── Charger limits ───────────────────────────────
flow.set('MIN_CURRENT', 6);           // A  — minimum Feyree accepts
flow.set('MAX_CURRENT', 16);          // A  — Feyree hardware maximum

// ── System ───────────────────────────────────────
flow.set('PHASES', 3);                // number of phases
flow.set('VOLTAGE', 230);             // V per phase

// ── Ramp limits (Feyree limitation) ─────────────
flow.set('MAX_RAMP_UP', 6);           // A  — max increase per 30s step
flow.set('MAX_RAMP_DOWN', 2);         // A  — max decrease per 30s step

// ── Grid setpoint ────────────────────────────────
flow.set('GRID_SETPOINT', 0);         // W  — negative = keep X watts export margin
                                      //      e.g. -200 = always keep 200W exporting

// ── Mode values (do not change) ──────────────────
flow.set('AUTO_MODE_VALUE', 1);       // 0=Manual 1=Auto 2=Scheduled

node.status({fill:'green', shape:'dot', text:'Config OK'});
return null;

const d = msg.payload;
if (d && d.deviceInstance && d.deviceInstance.ev1 !== undefined) {
    flow.set('EV_INSTANCE', d.deviceInstance.ev1);
    node.status({fill:'green', shape:'dot', text:'ev1 instance: ' + d.deviceInstance.ev1});
} else {
    node.status({fill:'yellow', shape:'ring', text:'No ev1 in payload'});
}
return null;

if (msg.payload && msg.payload.value !== undefined) {
    const v = parseInt(msg.payload.value);
    flow.set('ev_status', v);
    const labels = {
        0:'Disconnected', 1:'Connected',
        2:'Charging',     3:'Charged',
        6:'Waiting for start'
    };
    node.status({
        fill:  v===2 ? 'green' : v===1 ? 'blue' : 'grey',
        shape: 'dot',
        text:  labels[v] || 'Status ' + v
    });
}
return null;

if (msg.payload && msg.payload.value !== undefined) {
    const v           = parseInt(msg.payload.value);
    const prev_mode   = flow.get('ev_mode');
    const MAX_CURRENT = flow.get('MAX_CURRENT') || 16;
    const PORTAL_ID   = flow.get('PORTAL_ID')   || '48e7da87b65f';
    const EV_INSTANCE = flow.get('EV_INSTANCE');

    flow.set('ev_mode', v);

    const labels = {0:'Manual', 1:'Auto', 2:'Scheduled'};
    node.status({
        fill:  v === 1 ? 'green' : 'grey',
        shape: 'dot',
        text:  labels[v] || 'Unknown (' + v + ')'
    });

    // ── Transition FROM Auto → Manual/Scheduled ──────────────────
    // Reset stored target so next Auto activation starts clean.
    // Publish SetCurrent = MAX_CURRENT to clear the stale Auto-mode
    // value that Victron keeps echoing on N/.../SetCurrent and that
    // was overwriting the user's manual current setting in HA.
    if (prev_mode === 1 && v !== 1 && EV_INSTANCE !== undefined) {
        flow.set('ev_target_current', 0);
        const base = 'W/' + PORTAL_ID + '/evcharger/' + EV_INSTANCE;
        node.warn('Mode Auto → ' + (labels[v] || v)
                + ' — releasing SetCurrent, reset to MAX: ' + MAX_CURRENT + 'A');
        return {
            payload: JSON.stringify({value: MAX_CURRENT}),
            topic:   base + '/SetCurrent'
        };
    }
}
return null;

// ── Read config ─────────────────────────────────
const PORTAL_ID          = flow.get('PORTAL_ID')          || '48e7da87b65f';
const EV_INSTANCE        = flow.get('EV_INSTANCE');
const MIN_SOC            = flow.get('MIN_SOC')            || 20;
const MIN_CURRENT        = flow.get('MIN_CURRENT')        || 6;
const MAX_CURRENT        = flow.get('MAX_CURRENT')        || 16;
const PHASES             = flow.get('PHASES')             || 3;
const VOLTAGE            = flow.get('VOLTAGE')            || 230;
const MAX_RAMP_DOWN      = flow.get('MAX_RAMP_DOWN')      || 2;
const MAX_RAMP_UP        = flow.get('MAX_RAMP_UP')        || 6;
const GRID_SETPOINT      = flow.get('GRID_SETPOINT')      || 0;
const MAX_BATT_DISCHARGE = flow.get('MAX_BATT_DISCHARGE') || 500;
const AUTO_MODE_VALUE    = flow.get('AUTO_MODE_VALUE')    || 1;

// ── Read live data ───────────────────────────────
const grid_l1       = flow.get('grid_l1')       || 0;
const grid_l2       = flow.get('grid_l2')       || 0;
const grid_l3       = flow.get('grid_l3')       || 0;
const grid_power    = grid_l1 + grid_l2 + grid_l3;
const battery_soc   = flow.get('battery_soc');
const battery_power = flow.get('battery_power') || 0;
const ev_power      = flow.get('ev_power')      || 0;
const ev_status     = flow.get('ev_status');
const ev_mode       = flow.get('ev_mode');
const prev_current  = flow.get('ev_target_current') || 0;

const base = 'W/' + PORTAL_ID + '/evcharger/' + EV_INSTANCE;

// ── Guard: instance known? ───────────────────────
if (EV_INSTANCE === undefined || EV_INSTANCE === null) {
    node.status({fill:'yellow', shape:'ring', text:'Waiting for EV instance...'});
    return null;
}

// ── Guard: data available? ───────────────────────
if (battery_soc === undefined || battery_soc === null) {
    node.status({fill:'yellow', shape:'ring', text:'Waiting for battery SOC...'});
    return null;
}

// ── Guard: Auto mode only ────────────────────────
if (ev_mode !== AUTO_MODE_VALUE) {
    node.status({
        fill:  'grey',
        shape: 'ring',
        text:  ev_mode === 2         ? 'Scheduled mode — inactive'
             : ev_mode === 0         ? 'Manual mode — inactive'
             : ev_mode === undefined ? 'Mode unknown — waiting'
             : 'Mode ' + ev_mode + ' — inactive'
    });
    return null;
}

// ── Guard: car connected? ────────────────────────
if (ev_status === 0 || ev_status === undefined) {
    flow.set('ev_target_current', 0);
    node.status({fill:'grey', shape:'ring', text:'Car not connected'});
    return null;
}

// ── Guard: already fully charged? ───────────────
if (ev_status === 3) {
    flow.set('ev_target_current', 0);
    node.status({fill:'blue', shape:'dot', text:'Car fully charged'});
    return [
        null,
        {payload: JSON.stringify({value: 0}), topic: base + '/StartStop'}
    ];
}

// ── Guard: battery SOC too low ───────────────────
if (battery_soc < MIN_SOC) {
    flow.set('ev_target_current', MIN_CURRENT);
    node.status({
        fill:  'red',
        shape: 'dot',
        text:  'SOC ' + battery_soc.toFixed(0) + '% < min ' + MIN_SOC + '% — stopped'
    });
    return [
        {payload: JSON.stringify({value: MIN_CURRENT}), topic: base + '/SetCurrent'},
        {payload: JSON.stringify({value: 0}),           topic: base + '/StartStop'}
    ];
}

// ── Surplus calculation ──────────────────────────
// grid_power negative = exporting, positive = importing
// available_watts = what we can redirect to EV without importing
const available_watts = ev_power - grid_power + GRID_SETPOINT;
let target_current = available_watts / (PHASES * VOLTAGE);

// ── Battery discharge limit ──────────────────────
if (battery_power < -MAX_BATT_DISCHARGE && target_current > prev_current) {
    target_current = prev_current - MAX_RAMP_DOWN;
}

target_current = Math.max(0, Math.min(target_current, MAX_CURRENT));

// ── Apply ramp limits ────────────────────────────
let new_current;
if (target_current < MIN_CURRENT) {
    new_current = 0;
} else if (target_current >= prev_current) {
    new_current = Math.min(prev_current + MAX_RAMP_UP, target_current, MAX_CURRENT);
} else {
    new_current = Math.max(prev_current - MAX_RAMP_DOWN, target_current, MIN_CURRENT);
}

new_current = Math.round(new_current);
const should_charge = new_current >= MIN_CURRENT;
const kw = (new_current * PHASES * VOLTAGE / 1000).toFixed(1);

flow.set('ev_target_current', new_current);

node.status({
    fill:  should_charge ? 'green' : 'yellow',
    shape: 'dot',
    text:  (should_charge
                ? new_current + 'A / ' + kw + 'kW'
                : 'paused — below min ' + MIN_CURRENT + 'A')
         + ' | surplus:' + available_watts.toFixed(0) + 'W'
         + ' | SOC:' + battery_soc.toFixed(0) + '%'
         + ' | grid:' + grid_power.toFixed(0) + 'W'
});

return [
    {payload: JSON.stringify({value: new_current}),           topic: base + '/SetCurrent'},
    {payload: JSON.stringify({value: should_charge ? 1 : 0}), topic: base + '/StartStop'}
];
